16	//
17	// RBTDRC — crucible test cases for theurge end-to-end testing
18	//
19	// Cases execute inside a charged crucible (sentry + pentacle + bottle).
20	// Thread-local context bridges the static case function signature with
21	// the mutable invocation context needed for tabtarget calls.
22	
23	use std::cell::RefCell;
24	use std::io::Write;
25	use std::path::Path;
26	use std::process::{Command, Stdio};
27	
28	use crate::case;
29	use crate::rbtdre_engine::{
30	    rbtdre_resolve_fail_fast, rbtdre_Disposition, rbtdre_Section, rbtdre_Verdict,
31	};
32	use crate::rbtdri_invocation::{
33	    rbtdri_Context, rbtdri_invoke, rbtdri_invoke_global, rbtdri_invoke_imprint,
34	    rbtdri_parse_ifrit_verdict, rbtdri_read_burv_fact,
35	};
36	use crate::rbtdrm_manifest::{
37	    RBTDRM_COLOPHON_ABJURE, RBTDRM_COLOPHON_ACCESS_PROBE, RBTDRM_COLOPHON_BARK,
38	    RBTDRM_COLOPHON_FIAT, RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE, RBTDRM_COLOPHON_KLUDGE,
39	    RBTDRM_COLOPHON_ORDAIN, RBTDRM_COLOPHON_PLUMB_COMPACT, RBTDRM_COLOPHON_PLUMB_FULL,
40	    RBTDRM_COLOPHON_REKON_HALLMARK, RBTDRM_COLOPHON_SUMMON, RBTDRM_COLOPHON_TALLY,
41	    RBTDRM_COLOPHON_VOUCH, RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE, RBTDRM_COLOPHON_WRIT,
42	};
43	
44	// ── Thread-local invocation context ──────────────────────────
45	
46	/// Ifrit binary name inside the bottle container.
47	const RBTDRC_IFRIT_BINARY: &str = "rbid";
48	
49	/// Test connectivity target — ICANN-owned, stable single /20 CIDR (192.0.32.0/20)
50	const RBTDRC_CONNECTIVITY_DOMAIN: &str = "www.internic.net";
51	
52	thread_local! {
53	    static RBTDRC_CTX: RefCell<Option<rbtdri_Context>> = RefCell::new(None);
54	}
55	
56	/// Store invocation context for case functions. Called before run_sections.
57	pub fn rbtdrc_set_context(ctx: rbtdri_Context) {
58	    RBTDRC_CTX.with(|c| *c.borrow_mut() = Some(ctx));
59	}
60	
61	/// Retrieve invocation context after cases complete. Called for quench.
62	pub fn rbtdrc_take_context() -> rbtdri_Context {
63	    RBTDRC_CTX.with(|c| {
64	        c.borrow_mut()
65	            .take()
66	            .expect("rbtdrc: no context — was rbtdrc_set_context called?")
67	    })
68	}
69	
70	pub(crate) fn rbtdrc_with_ctx<F>(f: F) -> rbtdre_Verdict
71	where
72	    F: FnOnce(&mut rbtdri_Context) -> rbtdre_Verdict,
73	{
74	    RBTDRC_CTX.with(|c| {
75	        let mut opt = c.borrow_mut();
76	        let ctx = opt
77	            .as_mut()
78	            .expect("rbtdrc: no invocation context for case execution");
79	        f(ctx)
80	    })
81	}
82	
83	// ── Helpers ──────────────────────────────────────────────────
84	
85	/// Invoke ifrit inside the bottle via bark, saving stdout/stderr to case dir.
86	fn rbtdrc_invoke_ifrit(
87	    ctx: &mut rbtdri_Context,
88	    attack: &str,
89	    dir: &Path,
90	) -> rbtdre_Verdict {
91	    let result = match rbtdri_invoke(ctx, RBTDRM_COLOPHON_BARK, &[RBTDRC_IFRIT_BINARY, attack]) {
92	        Ok(r) => r,
93	        Err(e) => return rbtdre_Verdict::Fail(format!("bark invocation error: {}", e)),
94	    };
95	    let _ = std::fs::write(dir.join("bark-stdout.txt"), &result.stdout);
96	    let _ = std::fs::write(dir.join("bark-stderr.txt"), &result.stderr);
97	    rbtdri_parse_ifrit_verdict(&result.stdout, result.exit_code)
98	}
99	
100	/// Invoke ifrit inside the bottle via bark with extra arguments.

