130	/// Write verdict and detail to a trace file in the case temp directory.
131	fn rbtdre_write_trace(case_dir: &Path, display_name: &str, verdict: &rbtdre_Verdict) {
132	    let content = match verdict {
133	        rbtdre_Verdict::Pass => format!("PASSED: {}\n", display_name),
134	        rbtdre_Verdict::Fail(detail) => format!("FAILED: {}\n\n{}\n", display_name, detail),
135	        rbtdre_Verdict::Skip(reason) => {
136	            format!("SKIPPED: {}\n\nReason: {}\n", display_name, reason)
137	        }
