152	/// Run all sections sequentially, dispatching each case with per-case temp dir isolation.
153	pub fn rbtdre_run_sections(
154	    sections: &[rbtdre_Section],
155	    colors: &rbtdre_Colors,
156	    fail_fast: bool,
157	    root_temp: &Path,
158	) -> Result<rbtdre_RunResult, String> {
159	    let mut passed = 0usize;
160	    let mut failed = 0usize;
161	    let mut skipped = 0usize;
162	
163	    'outer: for section in sections {
164	        eprintln!(
165	            "\n{}--- {} ---{}",
166	            colors.white, section.name, colors.reset
167	        );
168	
169	        for case in section.cases {
170	            let case_dir = root_temp.join(case.name);
171	            std::fs::create_dir_all(&case_dir).map_err(|e| {
172	                format!("rbtd: failed to create case dir '{}': {}", case.name, e)
173	            })?;
174	
175	            let verdict = (case.func)(&case_dir);
176	            rbtdre_write_trace(&case_dir, case.name, &verdict);
177	
178	            match &verdict {
179	                rbtdre_Verdict::Pass => {
180	                    eprintln!("{}PASSED:{} {}", colors.green, colors.reset, case.name);
181	                    passed += 1;
182	                }
183	                rbtdre_Verdict::Fail(_) => {
184	                    eprintln!("{}FAILED:{} {}", colors.red, colors.reset, case.name);
185	                    failed += 1;
186	                    if fail_fast {
187	                        break 'outer;
188	                    }
189	                }
190	                rbtdre_Verdict::Skip(_) => {
191	                    eprintln!(
192	                        "{}SKIPPED:{} {}",
193	                        colors.yellow, colors.reset, case.name
194	                    );
195	                    skipped += 1;
196	                }
197	            }
198	        }
199	    }
200	
201	    Ok(rbtdre_RunResult {
202	        passed,
203	        failed,
204	        skipped,
205	        temp_dir: root_temp.to_path_buf(),
206	    })
