211	    let total = result.passed + result.failed + result.skipped;
212	    let (color, end_color) = if result.failed > 0 {
213	        (colors.red, colors.reset)
214	    } else {
215	        (colors.green, colors.reset)
216	    };
217	
218	    eprintln!(
219	        "\n{}{} passed, {} failed, {} skipped ({} total){}",
220	        color, result.passed, result.failed, result.skipped, total, end_color,
221	    );
