30	// ── Helpers ──────────────────────────────────────────────────
31	
32	/// Sub-assertion within a case: run bash snippet, check exit code.
33	struct RbtdrfSub {
34	    label: &'static str,
35	    setup: &'static str,
36	    command: &'static str,
37	    expect_ok: bool,
38	}
39	
40	impl RbtdrfSub {
41	    const fn ok(label: &'static str, setup: &'static str) -> Self {
42	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: true }
43	    }
44	    const fn fatal(label: &'static str, setup: &'static str) -> Self {
45	        Self { label, setup, command: "buv_vet \"TEST\"", expect_ok: false }
46	    }
47	    const fn ok_cmd(label: &'static str, setup: &'static str, command: &'static str) -> Self {
48	        Self { label, setup, command, expect_ok: true }
