        rbtdre_Verdict::Skip(d) => panic!("{}: expected Pass, got Skip({})", label, d),
    }
}

fn rbtdtl_assert_fail_with(verdict: &rbtdre_Verdict, needle: &str, label: &str) {
    match verdict {
        rbtdre_Verdict::Fail(d) => assert!(
            d.contains(needle),
